import{_ as e,o as t,c as r,ag as i}from"./chunks/framework.CAXxHpAX.js";const b=JSON.parse('{"title":"第 21 章 迁移学习","description":"","frontmatter":{},"headers":[],"relativePath":"ml/transfer-learning-pretraining.md","filePath":"ml/transfer-learning-pretraining.md","lastUpdated":1777721040000}'),n={name:"ml/transfer-learning-pretraining.md"};function d(p,a,l,s,o,h){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="第-21-章-迁移学习" tabindex="-1">第 21 章 迁移学习 <a class="header-anchor" href="#第-21-章-迁移学习" aria-label="Permalink to &quot;第 21 章 迁移学习&quot;">​</a></h1><p>深度模型通常需要大量数据和算力。如果每个任务都从零开始训练，成本很高，也容易过拟合。迁移学习的思想是：先在大规模数据上学习通用表示，再把这些表示迁移到新的任务中。</p><p>预训练模型之所以有效，是因为很多任务共享底层结构。图像任务共享边缘、纹理、形状等视觉特征；文本任务共享词义、语法和上下文关系。预训练模型先学到这些通用表示，再用较少的任务数据进行调整。</p><h2 id="_21-1-特征提取" tabindex="-1">21.1 特征提取 <a class="header-anchor" href="#_21-1-特征提取" aria-label="Permalink to &quot;21.1 特征提取&quot;">​</a></h2><p>最简单的迁移方式是把预训练模型当作特征提取器。</p><p>例如图像分类中，可以使用在 ImageNet 上预训练的 VGG 或 ResNet。去掉最后的分类层，把中间层输出作为图像特征，再训练一个新的分类器，例如 SVM 或线性分类层。</p><p>这种方法适合数据量较小、目标任务和预训练任务相近的场景。因为大部分网络参数被冻结，训练成本低，也不容易过拟合。</p><p>流程可以写成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入图像 -&gt; 预训练 CNN -&gt; 特征向量 -&gt; 新分类器</span></span></code></pre></div><h2 id="_21-2-微调" tabindex="-1">21.2 微调 <a class="header-anchor" href="#_21-2-微调" aria-label="Permalink to &quot;21.2 微调&quot;">​</a></h2><p>微调会在新任务上继续训练预训练模型的部分或全部参数。</p><p>如果新任务数据较少，通常只训练顶部几层，冻结底层特征提取层。如果新任务数据较多，或者和预训练任务差异较大，可以解冻更多层甚至全模型微调。</p><p>经验上，微调时学习率通常要比从零训练小。原因是预训练参数已经包含有用表示，过大的学习率可能破坏这些表示。</p><p>可以按下面原则选择：</p><table tabindex="0"><thead><tr><th>数据量</th><th>任务相似度</th><th>做法</th></tr></thead><tbody><tr><td>少</td><td>高</td><td>冻结主体，只训练分类头</td></tr><tr><td>少</td><td>低</td><td>冻结底层，微调高层</td></tr><tr><td>多</td><td>高</td><td>微调高层或全模型</td></tr><tr><td>多</td><td>低</td><td>全模型微调，但使用较小学习率</td></tr></tbody></table><h2 id="_21-3-视觉预训练" tabindex="-1">21.3 视觉预训练 <a class="header-anchor" href="#_21-3-视觉预训练" aria-label="Permalink to &quot;21.3 视觉预训练&quot;">​</a></h2><p>视觉任务中，ImageNet 预训练长期是常见做法。浅层卷积核通常学习边缘、颜色和纹理，这些特征在许多视觉任务中都能复用。</p><p>例如医学图像数据量较少时，可以先使用 ImageNet 预训练模型，再在医学数据上微调。虽然自然图像和医学图像不同，但底层视觉特征仍可能提供较好的初始化。</p><p>使用预训练模型并不意味着一定更好。如果目标数据和预训练数据差异太大，迁移效果可能有限，甚至出现负迁移。</p><h2 id="_21-4-nlp-中的预训练" tabindex="-1">21.4 NLP 中的预训练 <a class="header-anchor" href="#_21-4-nlp-中的预训练" aria-label="Permalink to &quot;21.4 NLP 中的预训练&quot;">​</a></h2><p>自然语言处理中，预训练模型先在大规模语料上学习语言规律，再迁移到分类、问答、摘要、信息抽取等任务。</p><p>BERT 是典型的预训练语言模型。它的预训练任务包括：</p><ul><li>掩码语言模型。</li><li>下一句预测。</li></ul><p>掩码语言模型会随机遮住部分 token，让模型根据上下文预测被遮住的词。这样模型能学习双向上下文表示。</p><h2 id="_21-5-bert-微调" tabindex="-1">21.5 BERT 微调 <a class="header-anchor" href="#_21-5-bert-微调" aria-label="Permalink to &quot;21.5 BERT 微调&quot;">​</a></h2><p>使用 BERT 做情感分析时，通常在 BERT 顶部加一个分类层。输入句子经过 BERT 得到表示，再由分类层输出情感类别。</p><p>典型流程：</p><ol><li>加载预训练 BERT。</li><li>添加任务相关输出层。</li><li>用任务数据训练分类层和部分 BERT 参数。</li><li>在验证集上选择最好的学习率和训练轮数。</li></ol><p>如果数据很少，可以冻结大部分层，只训练分类头；如果数据较多，可以微调整个模型。</p><h2 id="_21-6-词嵌入" tabindex="-1">21.6 词嵌入 <a class="header-anchor" href="#_21-6-词嵌入" aria-label="Permalink to &quot;21.6 词嵌入&quot;">​</a></h2><p>词嵌入把离散词映射到低维稠密向量空间。</p><p>one-hot 表示虽然简单，但维度高且稀疏，并且不能表达词之间的相似性。词嵌入则可以让语义相近的词在向量空间中更接近。</p><p>例如“国王”和“王后”、“北京”和“中国”之间可能在向量空间中形成有意义的关系。</p><p>Word2Vec 是经典词向量模型。现代系统中还会使用 BGE、Qwen embedding 等模型生成句子或文档级向量。</p><h2 id="_21-7-embedding、reranker-和生成模型" tabindex="-1">21.7 Embedding、Reranker 和生成模型 <a class="header-anchor" href="#_21-7-embedding、reranker-和生成模型" aria-label="Permalink to &quot;21.7 Embedding、Reranker 和生成模型&quot;">​</a></h2><p>在 RAG 或搜索系统中，Embedding、Reranker 和生成模型分工不同。</p><p>Embedding 模型负责把查询和文档编码成向量，用于快速召回候选文档。</p><p>Reranker 模型负责对候选文档重新排序。它通常比 embedding 召回更精细，但计算成本更高。</p><p>生成模型负责根据最终上下文生成答案。</p><p>所以它们的关系通常是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Embedding 召回 -&gt; Reranker 精排 -&gt; 生成模型回答</span></span></code></pre></div><p>如果题目问某个模型是否属于词向量模型，要看它的主要功能。如果是 reranker，它通常不是词向量模型，而是排序模型。</p><h2 id="_21-8-使用预训练模型的风险" tabindex="-1">21.8 使用预训练模型的风险 <a class="header-anchor" href="#_21-8-使用预训练模型的风险" aria-label="Permalink to &quot;21.8 使用预训练模型的风险&quot;">​</a></h2><p>预训练模型不是万能的。使用时要注意：</p><ul><li>预训练数据和目标任务是否相近。</li><li>微调数据是否足够干净。</li><li>是否存在数据泄漏。</li><li>模型是否学到了不适合当前场景的偏差。</li><li>输出是否需要人工审核。</li></ul><p>迁移学习的正确用法是利用已有表示，而不是盲目相信预训练模型一定适合所有任务。</p>',46)])])}const g=e(n,[["render",d]]);export{b as __pageData,g as default};
